import React from 'react';
import { BrowserRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import { Provider, useSelector } from 'react-redux';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import store from './store';
import Sidebar from './components/common/Sidebar';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import PatientsPage from './pages/PatientsPage';
import AppointmentsPage from './pages/AppointmentsPage';
import './styles/global.css';

function ProtectedLayout() {
  const { token } = useSelector((s) => s.auth);
  if (!token) return <Navigate to="/login" replace />;
  return (
    <div className="layout">
      <Sidebar />
      <main className="main-content"><Outlet /></main>
    </div>
  );
}

function DoctorsPage() {
  return <div className="page-header"><div><h2>Doctors</h2><p>Manage doctor records — implement similar to Patients page</p></div></div>;
}

function BillingPage() {
  return <div className="page-header"><div><h2>Billing</h2><p>Manage bills — implement similar to Appointments page</p></div></div>;
}

function AppRoutes() {
  const { token } = useSelector((s) => s.auth);
  return (
    <Routes>
      <Route path="/login" element={token ? <Navigate to="/" replace /> : <LoginPage />} />
      <Route element={<ProtectedLayout />}>
        <Route path="/"             element={<DashboardPage />} />
        <Route path="/patients"     element={<PatientsPage />} />
        <Route path="/doctors"      element={<DoctorsPage />} />
        <Route path="/appointments" element={<AppointmentsPage />} />
        <Route path="/billing"      element={<BillingPage />} />
      </Route>
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

export default function App() {
  return (
    <Provider store={store}>
      <BrowserRouter>
        <AppRoutes />
        <ToastContainer position="top-right" autoClose={3000} />
      </BrowserRouter>
    </Provider>
  );
}
